void update_time_digital_360(int second, int minute, int hour, bool mode, bool am, int day, int month, int year, int weekday)
{
#ifdef ENABLE_FACE_DIGITAL_360
    if (!face_digital_360)
    {
        return;
    }
	lv_img_set_src(face_digital_360_19_137322, face_digital_360_dial_img_19_137322_group[(month / 1) % 10]);
	lv_img_set_src(face_digital_360_20_137322, face_digital_360_dial_img_19_137322_group[(month / 10) % 10]);
	lv_img_set_src(face_digital_360_21_137322, face_digital_360_dial_img_19_137322_group[(day / 1) % 10]);
	lv_img_set_src(face_digital_360_22_137322, face_digital_360_dial_img_19_137322_group[(day / 10) % 10]);
	lv_img_set_src(face_digital_360_25_148985, face_digital_360_dial_img_25_148985_group[(hour / 1) % 10]);
	lv_img_set_src(face_digital_360_26_148985, face_digital_360_dial_img_25_148985_group[(hour / 10) % 10]);
	lv_img_set_src(face_digital_360_27_148985, face_digital_360_dial_img_25_148985_group[(minute / 1) % 10]);
	lv_img_set_src(face_digital_360_28_148985, face_digital_360_dial_img_25_148985_group[(minute / 10) % 10]);
	lv_img_set_src(face_digital_360_30_199157, face_digital_360_dial_img_30_199157_group[((weekday + 6) / 1) % 7]);

#endif
}

